The Circuit Breaker pattern prevents cascading failures in microservices by stopping requests to failing services. It monitors for failures and temporarily blocks calls.

States:
1. CLOSED: Normal operation
2. OPEN: Failing service, requests blocked
3. HALF_OPEN: Testing if service recovered

```java
// Using Resilience4j - Modern Implementation
@Configuration
public class CircuitBreakerConfig {

    @Bean
    public CircuitBreakerRegistry circuitBreakerRegistry() {
        CircuitBreakerConfig config = CircuitBreakerConfig.custom()
            .failureRateThreshold(50)           // Open after 50% failures
            .slowCallRateThreshold(50)          // Open after 50% slow calls
            .slowCallDurationThreshold(Duration.ofSeconds(2))
            .waitDurationInOpenState(Duration.ofSeconds(30))
            .permittedNumberOfCallsInHalfOpenState(3) // Try 3 calls when half-open
            .automaticTransitionFromOpenToHalfOpenEnabled(true)
            .recordExceptions(IOException.class, TimeoutException.class)
            .ignoreExceptions(BusinessException.class) // Don't count as failure
            .build();

        return CircuitBreakerRegistry.of(config);
    }
}

// Service using Circuit Breaker
@Service
public class PaymentService {

    @Autowired
    private CircuitBreakerRegistry registry;

    private final RestTemplate restTemplate = new RestTemplate();
    private final String paymentApiUrl = "http://payment-service/api/pay";

    @Retry(name = "paymentService", fallback = "fallbackProcess")
    @CircuitBreaker(name = "paymentService", fallbackMethod = "fallbackProcess")
    public PaymentResponse processPayment(PaymentRequest request) {
        CircuitBreaker cb = registry.circuitBreaker("paymentService");
        return cb.executeSupplier(() -> {
            // Call external payment service
            return restTemplate.postForObject(paymentApiUrl, request, PaymentResponse.class);
        });
    }

    // Fallback method when circuit is open
    public PaymentResponse fallbackProcess(PaymentRequest request, Exception e) {
        System.out.println("Circuit breaker open, using fallback");
        return new PaymentResponse(
            "PENDING", 
            "Payment service temporarily unavailable. Will retry.",
            request.getTransactionId()
        );
    }
}

// Annotation-based Configuration
@Service
public class OrderService {

    @Autowired
    private PaymentService paymentService;

    @CircuitBreaker(name = "orderService", fallbackMethod = "fallback")
    @Retry(name = "orderService", fallback = "fallback")
    @Timeout(name = "orderService")
    public Order createOrder(OrderRequest request) {
        // Business logic
        // If fails 50% of the time over 10 calls, circuit opens
        // After 30 seconds, tries half-open (allows 3 test calls)
        // If those succeed, circuit closes again
        return new Order();
    }

    public Order fallback(OrderRequest request, Exception e) {
        // Return cached response or default
        return new Order("PENDING");
    }
}

// application.yml Configuration
/*
resilience4j:
  circuitbreaker:
    configs:
      default:
        registerHealthIndicator: true
        slidingWindowSize: 10
        minimumNumberOfCalls: 5
        permittedNumberOfCallsInHalfOpenState: 3
        automaticTransitionFromOpenToHalfOpenEnabled: true
        waitDurationInOpenState: 1s
        failureRateThreshold: 50
        eventConsumerBufferSize: 10
    instances:
      orderService:
        baseConfig: default
        waitDurationInOpenState: 2s
      paymentService:
        baseConfig: default
        failureRateThreshold: 60
*/

// Monitoring Circuit Breaker State
@Component
public class CircuitBreakerMonitor {

    @Autowired
    private CircuitBreakerRegistry registry;

    @Scheduled(fixedDelay = 10000)
    public void monitorCircuitBreakers() {
        registry.getAllCircuitBreakers().forEach(cb -> {
            CircuitBreaker.State state = cb.getState();
            System.out.println("Circuit Breaker: " + cb.getName() + 
                             ", State: " + state +
                             ", Failures: " + cb.getMetrics().getNumberOfFailedCalls());
        });
    }
}
```

Benefits: Prevents cascading failures, provides fallback options, monitors service health, automatic recovery. Resilience4j offers circuit breakers, retries, timeouts, bulkheads all integrated.

