An API Gateway is a single entry point for all client requests in microservices architecture. It handles routing, authentication, rate limiting, and protocol translation.

Responsibilities:
1. Request routing to services
2. Authentication/Authorization
3. Rate limiting
4. Request/Response transformation
5. Aggregation

```java
// Spring Cloud Gateway Configuration
@Configuration
public class GatewayConfig {

    @Bean
    public RouteLocator routes(RouteLocatorBuilder builder) {
        return builder.routes()
            // Route to User Service
            .route("user-service", r -> r
                .path("/users/**")
                .uri("lb://user-service")) // Load balanced URI

            // Route to Order Service with path rewrite
            .route("order-service", r -> r
                .path("/orders/**")
                .filters(f -> f.rewritePath("/orders/(?<id>.*)", "/api/orders/${id}"))
                .uri("lb://order-service"))

            // Route with custom filter
            .route("payment-service", r -> r
                .path("/payments/**")
                .filters(f -> f
                    .addRequestHeader("X-Request-ID", UUID.randomUUID().toString())
                    .addResponseHeader("X-Response-Time", "")
                    .stripPrefix(1))
                .uri("lb://payment-service"))

            .build();
    }
}

// application.yml Configuration
/*
spring:
  cloud:
    gateway:
      routes:
        - id: user-service
          uri: lb://user-service
          predicates:
            - Path=/users/**
          filters:
            - StripPrefix=1

        - id: order-service
          uri: lb://order-service
          predicates:
            - Path=/orders/**
          filters:
            - RewritePath=/orders/(?<id>.*),/api/orders/${id}
            - AddRequestHeader=X-Request-ID,request-id
            - AuthFilter
*/

// Custom Gateway Filter
@Component
public class JwtAuthenticationFilter implements GlobalFilter, Ordered {

    @Autowired
    private JwtTokenProvider tokenProvider;

    @Override
    public Mono<Void> filter(ServerWebExchange exchange, GatewayFilterChain chain) {
        ServerHttpRequest request = exchange.getRequest();

        // Skip auth for public endpoints
        if (isPublicEndpoint(request.getPath().value())) {
            return chain.filter(exchange);
        }

        try {
            // Extract JWT from Authorization header
            String token = extractToken(request);
            if (token != null && tokenProvider.validateToken(token)) {
                String username = tokenProvider.getUsernameFromToken(token);

                // Add user info to request headers
                ServerHttpRequest newRequest = request.mutate()
                    .header("X-User-ID", username)
                    .build();

                ServerWebExchange newExchange = exchange.mutate().request(newRequest).build();
                return chain.filter(newExchange);
            }
        } catch (Exception e) {
            // Token invalid
        }

        return Mono.error(new UnauthorizedException("Unauthorized"));
    }

    @Override
    public int getOrder() {
        return Ordered.HIGHEST_PRECEDENCE;
    }

    private String extractToken(ServerHttpRequest request) {
        String authHeader = request.getHeaders().getFirst(HttpHeaders.AUTHORIZATION);
        if (authHeader != null && authHeader.startsWith("Bearer ")) {
            return authHeader.substring(7);
        }
        return null;
    }

    private boolean isPublicEndpoint(String path) {
        return path.contains("/public") || path.contains("/auth/login");
    }
}

// Rate Limiting Filter
@Component
public class RateLimitingFilter implements GlobalFilter, Ordered {

    @Autowired
    private RedisTemplate<String, Integer> redisTemplate;

    private final int MAX_REQUESTS = 100;
    private final long WINDOW_SIZE = 60; // 1 minute

    @Override
    public Mono<Void> filter(ServerWebExchange exchange, GatewayFilterChain chain) {
        String clientIp = getClientIp(exchange.getRequest());
        String key = "rate-limit:" + clientIp;

        Integer requests = redisTemplate.opsForValue().get(key);
        if (requests == null) {
            redisTemplate.opsForValue().set(key, 1, Duration.ofSeconds(WINDOW_SIZE));
        } else if (requests >= MAX_REQUESTS) {
            return Mono.error(new RuntimeException("Rate limit exceeded"));
        } else {
            redisTemplate.opsForValue().increment(key);
        }

        return chain.filter(exchange);
    }

    @Override
    public int getOrder() {
        return Ordered.LOWEST_PRECEDENCE;
    }

    private String getClientIp(ServerHttpRequest request) {
        String xForwardedFor = request.getHeaders().getFirst("X-Forwarded-For");
        if (xForwardedFor != null) {
            return xForwardedFor.split(",")[0];
        }
        return request.getRemoteAddress().getAddress().getHostAddress();
    }
}
```

Gateway Benefits: Single authentication point, circuit breaking at gateway level, rate limiting, request logging, cross-cutting concerns. Spring Cloud Gateway is non-blocking and reactive, better than older Zuul.

Feign is a declarative HTTP client that simplifies service-to-service communication in microservices. It eliminates boilerplate RestTemplate code.

