@FeignClient(name = "user-service", url = "http://localhost:8081")
public interface UserServiceClient {

    @GetMapping("/users/{id}")
    User getUserById(@PathVariable("id") Long id);

    @PostMapping("/users")
    User createUser(@RequestBody User user);

    @PutMapping("/users/{id}")
    User updateUser(@PathVariable("id") Long id, @RequestBody User user);

    @DeleteMapping("/users/{id}")
    void deleteUser(@PathVariable("id") Long id);
}

// 2. Service Discovery Integration
@FeignClient(
    name = "user-service", // Service name in Eureka
    fallback = UserServiceClientFallback.class, // Fallback on failure
    configuration = FeignConfig.class
)
public interface DiscoveryUserClient {
    @GetMapping("/users/{id}")
    User getUser(@PathVariable Long id);
}

// 3. Fallback Implementation
@Component
public class UserServiceClientFallback implements DiscoveryUserClient {
    @Override
    public User getUser(Long id) {
        System.out.println("User service unavailable, returning fallback");
        return new User(id, "Fallback User");
    }
}

// 4. Feign Configuration
@Configuration
public class FeignConfig {

    @Bean
    public Logger.Level feignLoggerLevel() {
        return Logger.Level.FULL; // Log request/response
    }

    @Bean
    public Request.Options options() {
        return new Request.Options(
            5, TimeUnit.SECONDS,  // Connection timeout
            10, TimeUnit.SECONDS, // Read timeout
            true
        );
    }

    @Bean
    public Retryer retryer() {
        return new Retryer.Default(
            100,      // Initial interval
            1000,     // Max interval
            3         // Max attempts
        );
    }

    @Bean
    public ErrorDecoder errorDecoder() {
        return (methodKey, response) -> {
            if (response.status() == 404) {
                return new RuntimeException("Not found: " + methodKey);
            }
            if (response.status() == 500) {
                return new RuntimeException("Server error");
            }
            return new RuntimeException("Error: " + response.status());
        };
    }
}

// 5. Using Feign Client in Service
@Service
public class OrderService {

    @Autowired
    private DiscoveryUserClient userClient;

    @Autowired
    private OrderRepository orderRepository;

    @Transactional
    public Order createOrder(Long userId, OrderRequest request) {
        // Fetch user from user-service
        User user = userClient.getUser(userId);

        if (user == null) {
            throw new RuntimeException("User not found");
        }

        Order order = new Order();
        order.setUserId(userId);
        order.setStatus("PENDING");

        return orderRepository.save(order);
    }
}

// 6. Request Interceptor for Headers
@Configuration
public class FeignInterceptorConfig {

    @Bean
    public RequestInterceptor requestInterceptor() {
        return requestTemplate -> {
            // Add common headers
            requestTemplate.header("X-Request-ID", UUID.randomUUID().toString());
            requestTemplate.header("Content-Type", "application/json");

            // Add authentication token if needed
            String token = getCurrentUserToken();
            if (token != null) {
                requestTemplate.header("Authorization", "Bearer " + token);
            }
        };
    }

    private String getCurrentUserToken() {
        // Get from SecurityContext or ThreadLocal
        return null;
    }
}

