Kafka is a distributed event streaming platform designed for high-throughput, low-latency message processing. It's essential for event-driven microservices.

Core Components:
1. Producer: Publishes messages
2. Broker: Stores messages
3. Consumer: Subscribes and processes messages
4. Topic: Categorized message queue
5. Partition: Parallel processing unit

```java
// 1. Producer Configuration
@Configuration
public class KafkaProducerConfig {

    @Bean
    public ProducerFactory<String, String> producerFactory() {
        Map<String, Object> configProps = new HashMap<>();
        configProps.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        configProps.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class);
        configProps.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class);
        configProps.put(ProducerConfig.ACKS_CONFIG, "all"); // Wait for all replicas
        configProps.put(ProducerConfig.RETRIES_CONFIG, 3);
        return new DefaultProducerFactory<>(configProps);
    }

    @Bean
    public KafkaTemplate<String, String> kafkaTemplate() {
        return new KafkaTemplate<>(producerFactory());
    }
}

// 2. Publishing Events
@Service
public class OrderEventPublisher {

    @Autowired
    private KafkaTemplate<String, String> kafkaTemplate;

    public void publishOrderCreated(Order order) {
        String message = objectMapper.writeValueAsString(order);
        // Async send with callback
        kafkaTemplate.send("order-events", order.getId().toString(), message)
            .addCallback(
                result -> System.out.println("Message sent: " + result.getRecordMetadata()),
                ex -> System.err.println("Failed to send: " + ex.getMessage())
            );
    }
}

// 3. Consumer Configuration
@Configuration
public class KafkaConsumerConfig {

    @Bean
    public ConsumerFactory<String, String> consumerFactory() {
        Map<String, Object> props = new HashMap<>();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "order-service-group");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest"); // Replay from start
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, false); // Manual commit
        return new DefaultConsumerFactory<>(props);
    }

    @Bean
    public ConcurrentKafkaListenerContainerFactory<String, String> kafkaListenerContainerFactory() {
        ConcurrentKafkaListenerContainerFactory<String, String> factory =
            new ConcurrentKafkaListenerContainerFactory<>();
        factory.setConsumerFactory(consumerFactory());
        factory.setConcurrency(3); // 3 concurrent consumers per partition
        return factory;
    }
}

// 4. Consuming Events
@Component
public class OrderEventConsumer {

    @Autowired
    private OrderService orderService;

    @KafkaListener(topics = "order-events", groupId = "order-service-group")
    public void consumeOrderEvent(ConsumerRecord<String, String> record, Acknowledgment ack) {
        try {
            Order order = objectMapper.readValue(record.value(), Order.class);
            System.out.println("Processing order: " + order.getId());
            orderService.processOrder(order);
            ack.acknowledge(); // Manual commit after successful processing
        } catch (Exception e) {
            System.err.println("Error processing order: " + e.getMessage());
            // Don't acknowledge, will retry
        }
    }
}

// 5. Topic and Partition Strategy
@Configuration
public class KafkaTopicConfig {

    @Bean
    public NewTopic orderEventsTopic() {
        return TopicBuilder.name("order-events")
            .partitions(3)              // 3 partitions for parallelism
            .replicas(2)                // Replication factor for HA
            .config("retention.ms", "604800000") // 7 days
            .build();
    }
}

// 6. Partition Assignment Strategy
/*
Partitions enable parallel processing:
- Messages with same key go to same partition (ordering guarantee)
- Different keys can go to different partitions (parallelism)
- Consumer group distributes partitions among consumers
*/

@Service
public class PaymentEventPublisher {

    @Autowired
    private KafkaTemplate<String, String> kafkaTemplate;

    public void publishPaymentProcessed(Payment payment) {
        // Same orderId key ensures all order events stay in order
        kafkaTemplate.send("payment-events", 
            payment.getOrderId().toString(), // Key for partitioning
            objectMapper.writeValueAsString(payment));
    }
}

