Kafka Guarantees: At-least-once delivery (with manual commit), partition ordering (per partition), replay capability, durability through replication. Essential for event-driven architectures, real-time analytics, and log aggregation.

Kafka Consumer is a component that subscribes to topics and processes messages. Consumer groups enable horizontal scaling and fault tolerance.

Key Concepts:
1. Consumer Group: Distributes processing across instances
2. Partition Assignment: Each consumer gets exclusive partitions
3. Offset: Position in partition (enables replay)
4. Rebalancing: Reassignment when consumers join/leave

```java
// 1. Basic Consumer
@Component
public class BasicKafkaConsumer {

    @KafkaListener(topics = "order-topic", groupId = "group-1")
    public void consume(String message) {
        System.out.println("Received: " + message);
    }
}

// 2. Consumer with Manual Commit (Exactly-once semantics)
@Component
public class ManualCommitConsumer {

    @KafkaListener(topics = "order-topic", groupId = "order-group")
    public void consume(ConsumerRecord<String, String> record, Acknowledgment ack) {
        try {
            // Process message
            Order order = objectMapper.readValue(record.value(), Order.class);
            System.out.println("Offset: " + record.offset() + ", Partition: " + record.partition());
            processOrder(order);

            // Only commit if processing succeeds
            ack.acknowledge();
        } catch (Exception e) {
            // Don't acknowledge - message will be reprocessed
            System.err.println("Failed to process: " + e.getMessage());
        }
    }
}

// 3. Batch Processing
@Component
public class BatchConsumer {

    @KafkaListener(
        topics = "order-topic",
        groupId = "batch-group",
        batch = "true"
    )
    public void consumeBatch(List<ConsumerRecord<String, String>> records,
                            Acknowledgment ack) {
        List<Order> orders = records.stream()
            .map(r -> objectMapper.readValue(r.value(), Order.class))
            .collect(Collectors.toList());

        // Process batch for efficiency
        orderRepository.saveAll(orders);
        ack.acknowledge();
    }
}

// 4. Consumer Configuration
@Configuration
public class KafkaConsumerConfig {

    @Bean
    public ConsumerFactory<String, String> consumerFactory() {
        Map<String, Object> props = new HashMap<>();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "my-group");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);

        // Offset reset behavior
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");
        // earliest: replay from beginning
        // latest: only new messages

        // Manual commit (disable auto)
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, false);

        // Session timeout (heartbeat)
        props.put(ConsumerConfig.SESSION_TIMEOUT_MS_CONFIG, "30000");

        // Poll interval for rebalancing
        props.put(ConsumerConfig.MAX_POLL_INTERVAL_MS_CONFIG, "300000");

        return new DefaultConsumerFactory<>(props);
    }

    @Bean
    public ConcurrentKafkaListenerContainerFactory<String, String> kafkaListenerContainerFactory() {
        ConcurrentKafkaListenerContainerFactory<String, String> factory =
            new ConcurrentKafkaListenerContainerFactory<>();
        factory.setConsumerFactory(consumerFactory());
        factory.setConcurrency(3); // 3 threads per partition
        factory.setBatchListener(false); // Single record mode
        return factory;
    }
}

