@Component
public class RebalancingListener implements ConsumerAwareListenerErrorHandler {

    @KafkaListener(topics = "order-topic")
    public void consume(String message) {
        // Process message
    }

    @EventListener
    public void onConsumerPartitionsRevoked(ConsumerPartitionsRevokedEvent event) {
