@Component
public class RetryableConsumer {

    @KafkaListener(topics = "order-topic")
    @Retry(maxAttempts = 3, backoff = @Backoff(delay = 1000))
    public void consume(String message) throws Exception {
        if (shouldFail()) {
            throw new Exception("Processing failed");
        }
        // Process message
    }

    @KafkaListener(topics = "order-topic.DLT")
    public void processDLT(String message) {
        System.err.println("Message sent to DLT: " + message);
    }
}
