Consumer Key Points: Offset tracks position in partition; consumer group distributes work; rebalancing handles failures; manual commit ensures exactly-once; batch processing improves throughput.

Event-Driven Architecture decouples services by communicating through events. Services emit events when state changes, and other services react to those events.

Benefits: Loose coupling, scalability, real-time responsiveness, easy to extend.
Challenges: Eventual consistency, debugging complexity, event schema versioning.

```java
// 1. Event Definition
public class OrderCreatedEvent {
    private Long orderId;
    private Long userId;
    private BigDecimal amount;
    private LocalDateTime createdAt;

    // Constructor, getters
    public OrderCreatedEvent(Long orderId, Long userId, BigDecimal amount) {
        this.orderId = orderId;
        this.userId = userId;
        this.amount = amount;
        this.createdAt = LocalDateTime.now();
    }
}

// 2. Event Publisher (Order Service)
@Service
public class OrderService {

    @Autowired
    private OrderRepository orderRepository;

    @Autowired
    private KafkaTemplate<String, String> kafkaTemplate;

    @Transactional
    public Order createOrder(OrderRequest request) {
        // Persist order
        Order order = new Order();
        order.setUserId(request.getUserId());
        order.setAmount(request.getAmount());
        order.setStatus("CREATED");

        Order savedOrder = orderRepository.save(order);

        // Emit event
        publishOrderCreatedEvent(savedOrder);
        return savedOrder;
    }

    private void publishOrderCreatedEvent(Order order) {
        OrderCreatedEvent event = new OrderCreatedEvent(
            order.getId(), order.getUserId(), order.getAmount()
        );

        try {
            String eventJson = objectMapper.writeValueAsString(event);
            kafkaTemplate.send("order-events", 
                order.getId().toString(),
                eventJson);
        } catch (JsonProcessingException e) {
            throw new RuntimeException("Failed to publish event", e);
        }
    }
}

// 3. Event Consumer (Payment Service)
@Service
public class PaymentService {

    @Autowired
    private PaymentRepository paymentRepository;

    @KafkaListener(topics = "order-events", groupId = "payment-service")
    public void handleOrderCreated(ConsumerRecord<String, String> record,
                                   Acknowledgment ack) {
        try {
            OrderCreatedEvent event = objectMapper.readValue(
                record.value(), OrderCreatedEvent.class
            );

            // React to event
            Payment payment = new Payment();
            payment.setOrderId(event.getOrderId());
            payment.setAmount(event.getAmount());
            payment.setStatus("PENDING");

            paymentRepository.save(payment);

            // Emit another event for next service
            publishPaymentCreatedEvent(payment);

            ack.acknowledge();
        } catch (Exception e) {
            System.err.println("Error processing order event: " + e.getMessage());
        }
    }
}

