// 5. Sagas Pattern for Distributed Transactions
@Service
public class OrderSaga {

    @Autowired
    private OrderService orderService;

    @Autowired
    private PaymentService paymentService;

    @Autowired
    private InventoryService inventoryService;

    // Choreography-based saga
    @KafkaListener(topics = "order-events")
    public void onOrderCreated(OrderCreatedEvent event) {
        try {
            // Step 1: Order created (already done)

            // Step 2: Create payment
            Payment payment = paymentService.createPayment(event);

            // Step 3: Reserve inventory
            inventoryService.reserveItems(event.getOrderId());

            // If all succeed, order is confirmed
            orderService.confirmOrder(event.getOrderId());
        } catch (Exception e) {
            // Compensating transaction: Rollback
            orderService.cancelOrder(event.getOrderId());
            paymentService.cancelPayment(event.getOrderId());
            inventoryService.releaseReservation(event.getOrderId());
        }
    }
}

