// 3. Manual Span Creation
@Component
public class ManualTracingExample {

    @Autowired
    private Tracer tracer;

    public void processOrder(Order order) {
        // Create custom span
        Span customSpan = tracer.nextSpan().name("process-order").start();

        try (
            Tracer.SpanInScope ws = tracer.withSpan(customSpan)) {
            // Logic here is traced
            validateOrder(order);
            saveOrder(order);
        } finally {
            customSpan.finish();
        }
    }
}

