@Component
public class TraceContextPropagation {

    @Autowired
    private Tracer tracer;

    @Autowired
    private KafkaTemplate<String, String> kafkaTemplate;

    public void publishEvent(String topic, String message) {
        // Get current trace context
        Span currentSpan = tracer.currentSpan();
        String traceId = currentSpan.context().traceId();

        // Send to Kafka with trace ID
        kafkaTemplate.send(topic, 
            buildMessage(message, traceId));
    }
}

// 5. Correlation ID for Logging
@Component
public class LoggingInterceptor implements ClientHttpRequestInterceptor {

    @Autowired
    private Tracer tracer;

    @Override
    public ClientHttpResponse intercept(HttpRequest request, byte[] body,
                                       ClientHttpRequestExecution execution) throws IOException {
        // Add trace ID to request headers
        Span span = tracer.currentSpan();
        if (span != null) {
            request.getHeaders().add("X-Trace-ID", span.context().traceId());
        }
        return execution.execute(request, body);
    }
}

