// 7. Custom Tags and Events
@Component
public class CustomTagsAndEvents {

    @Autowired
    private Tracer tracer;

    public void processPayment(Payment payment) {
        Span span = tracer.currentSpan();

        // Add custom tags
        span.tag("payment.amount", String.valueOf(payment.getAmount()));
        span.tag("payment.method", payment.getMethod());
        span.tag("user.id", String.valueOf(payment.getUserId()));

        // Add events for important points
        span.event("payment.started");

        try {
            // Process payment
            span.event("payment.processing");
        } catch (Exception e) {
            span.event("payment.failed");
            span.error(e);
        } finally {
            span.event("payment.completed");
        }
    }
}

