@Component
public class BaggageExample {

    @Autowired
    private Tracer tracer;

    public void setUserContext(String userId) {
        // Set baggage item (propagated across services)
        tracer.currentSpan().baggage("user-id").set(userId);
    }

    public String getUserContext() {
        // Read baggage from current span
        return tracer.currentSpan().baggage("user-id").get();
    }
}
